/* PasstheEPPP — Question Bank Batch 43
   85 new questions — Assessment, Development, Ethics, Research, Mixed */
(function(){
    if (typeof EPPPData === 'undefined') return;

    const batch43 = [
        // === Assessment (15) ===
        {domainId:5, q:"The Beck Depression Inventory-II (BDI-II) is a:", options:["A formal clinician-administered semi-structured diagnostic interview protocol","A self-report measure of depression severity over the past two weeks","An unstructured phenomenological projective psychological assessment","A standardized comprehensive broad-based adult intelligence measure"], answer:1, difficulty:"easy", rationale:"Correct: (B) BDI-II: 21-item self-report measuring depression severity over 2 weeks. Scores: 0-13 minimal, 14-19 mild, 20-28 moderate, 29-63 severe. Not a diagnostic tool — used for screening and tracking symptom severity.\n\nWhy others are wrong:\n(A) It's self-report, not clinician-administered\n(C) It's a structured self-report, not projective\n(D) It measures depression, not intelligence"},
        {domainId:5, q:"Face validity refers to:", options:["Whether the test instrument statistically converges and predicts future behavioral outcomes","Whether the test APPEARS to measure what it claims (from the test-taker's perspective)","The degree of statistical consistency across independent expert clinical raters","The empirical stability of measurement scores across multiple temporal administrations"], answer:1, difficulty:"easy", rationale:"Correct: (B) Face validity: does the test LOOK like it measures the right thing? Important for test-taker buy-in and cooperation, but NOT a psychometric property — a test can have good face validity but poor construct validity, or vice versa.\n\nWhy others are wrong:\n(A) Actually measuring what it claims = construct validity\n(C) Inter-rater agreement = inter-rater reliability\n(D) Test-retest stability = test-retest reliability"},
        {domainId:5, q:"Standard error of measurement (SEM) is MOST influenced by:", options:["The overall length and specific specific developmental normative sample size","The assessment instrument's empirical reliability — lower reliability produces larger SEM","The sheer volume and diversity of the representative normative comparison cohort","The instrument's superficial apparent face validity from the examinee perspective"], answer:1, difficulty:"medium", rationale:"Correct: (B) SEM = SD × √(1 - reliability). As reliability increases, SEM decreases. SEM creates confidence intervals around observed scores — accounting for measurement error. A test with r=.90 has much smaller SEM than one with r=.60.\n\nWhy others are wrong:\n(A) Test length affects reliability, which indirectly affects SEM\n(C) Number of test-takers affects normative data, not individual score precision\n(D) Face validity is unrelated to measurement error"},
        {domainId:5, q:"The PHQ-9 is a brief screening tool for:", options:["Generalized Anxiety Disorder and related severe somatic symptom clusters","Major Depressive Disorder and overall depressive symptom severity over two weeks","Borderline Personality Disorder and systemic pervasive trait pathology","Alcohol Use Disorder and subsequent physiological dependency mechanisms"], answer:1, difficulty:"easy", rationale:"Correct: (B) PHQ-9: 9-item self-report corresponding to DSM MDD criteria. Rates each symptom on 0-3 severity scale over past 2 weeks. Widely used in primary care. Scores ≥10 suggest clinically significant depression.\n\nWhy others are wrong:\n(A) Anxiety screening → GAD-7\n(C) Personality → MMPI-2, MCMI-IV\n(D) Substance use → AUDIT, DAST"},
        {domainId:5, q:"Convergent validity is demonstrated when a test:", options:["Shows theoretically expected systemic low correlations with unrelated constructs","Shows HIGH correlation with measures of the same or related underlying constructs","Predicts subsequent specific vocational or rigorous academic outcome criteria","Demonstrates profound absolute internal consistency across diverse scale items"], answer:1, difficulty:"medium", rationale:"Correct: (B) Convergent validity: high correlations with measures that should theoretically be related. An anxiety scale should correlate highly with other anxiety measures. Together with discriminant validity, it supports construct validity (Campbell & Fiske's multitrait-multimethod matrix).\n\nWhy others are wrong:\n(A) Low correlation with similar measures indicates POOR convergent validity\n(C) Predicting future behavior = predictive validity\n(D) Reliability ≠ validity"},
        {domainId:5, q:"The GAD-7 is a screening measure for:", options:["Major Depressive Disorder and profound persistent vegetative mood symptoms","Generalized Anxiety Disorder and broad anxiety symptom severity over two weeks","Schizophrenia spectrum clinical features including frank positive symptoms","Post-Traumatic Stress Disorder and trauma-related behavioral hyperarousal"], answer:1, difficulty:"easy", rationale:"Correct: (B) GAD-7: 7-item self-report for GAD. Rates anxiety symptoms over past 2 weeks on 0-3 scale. Scores: 5-9 mild, 10-14 moderate, 15-21 severe. Also valid as a screen for other anxiety disorders.\n\nWhy others are wrong:\n(A) Depression screening → PHQ-9, BDI-II\n(C) Schizophrenia → no single brief screening captures it; clinical interview needed\n(D) PTSD screening → PCL-5"},
        {domainId:5, q:"Factor analysis is used in test development to:", options:["Systematically maximize the overall length and reliability of testing protocols","Identify underlying latent factors that explain correlations among test items","Determine exact precise temporal stability metrics utilizing repeated measures","Establish rigorous predictive criterion outcome validity against external metrics"], answer:1, difficulty:"medium", rationale:"Correct: (B) Factor analysis groups items that correlate with each other into factors (latent constructs). Exploratory FA discovers factor structure; Confirmatory FA tests whether data fit a hypothesized structure. Essential for establishing construct validity.\n\nWhy others are wrong:\n(A) Factor analysis may actually lead to shorter tests by identifying redundant items\n(C) Test-retest requires administering the test twice\n(D) Predictive validity requires criterion data"},
        {domainId:5, q:"An IQ score of 85 falls at approximately the:", options:["The 50th percentile, functioning exactly precisely upon the normative population average","The 16th percentile, representing performance one standard deviation below the mean","The 2nd percentile, representing performance two standard deviations below the mean","The 84th percentile, representing performance one standard deviation above the mean"], answer:1, difficulty:"easy", rationale:"Correct: (B) IQ: mean=100, SD=15. Score 85 = 1 SD below mean ≈ 16th percentile. This falls in the 'Low Average' range (80-89). Approximately 84% of the population scores higher.\n\nWhy others are wrong:\n(A) 50th percentile = IQ 100\n(C) 2nd percentile = IQ 70 (2 SDs below mean)\n(D) 84th percentile = IQ 115 (1 SD above mean)"},
        {domainId:5, q:"The Personality Assessment Inventory (PAI) has a notable advantage over the MMPI-2 in that:", options:["It completely entirely entirely lacks any systemic dedicated internal validity metric scales","Items do not overlap across scales (non-overlapping items), making interpretation cleaner","It is substantially consistently shorter compared against every other established instrument","It intentionally uniquely exclusively entirely fundamentally ignores all clinical pathology"], answer:1, difficulty:"hard", rationale:"Correct: (B) Unlike the MMPI-2 where items can score on multiple scales (item overlap inflates inter-scale correlations), the PAI uses non-overlapping items — each item contributes to only one scale. This improves discriminant validity between scales.\n\nWhy others are wrong:\n(A) The PAI has validity scales (Inconsistency, Infrequency, Negative Impression, Positive Impression)\n(C) The PAI has 344 items — not the shortest\n(D) The PAI does assess clinical syndromes and personality"},
        {domainId:5, q:"The Conners Rating Scales are primarily used to assess:", options:["Severe chronic vegetative persistent neurobiological major depressive episodes in adults","ADHD symptoms and related externalizing behavioral concerns in children and adolescents","Deteriorating profound progressive widespread systemic cognitive memory decline in elderly","Acute pervasive persistent severe generalized actively active schizophrenic psychotic symptoms"], answer:1, difficulty:"easy", rationale:"Correct: (B) Conners scales: multi-informant (parent, teacher, self-report) rating scales for ADHD symptoms including inattention, hyperactivity-impulsivity, learning problems, executive functioning, defiance, and peer relations. Also includes validity scales.\n\nWhy others are wrong:\n(A) Depression → BDI, PHQ-9\n(C) Memory → WMS, RBMT\n(D) Psychosis → PANSS, BPRS"},
        {domainId:5, q:"Criterion-referenced tests differ from norm-referenced tests in that criterion-referenced tests:", options:["Systematically objectively longitudinally compare derived test scores to a normative sample","Evaluate performance explicitly against a fixed, predetermined absolute standard of mastery","Fundamentally inherently systematically possess exceptionally higher empirical reliability metrics","Strictly narrowly exclusively specifically apply specifically within formal academic environments"], answer:1, difficulty:"medium", rationale:"Correct: (B) Criterion-referenced: performance judged against a predefined standard (e.g., 'can the student multiply fractions?'). Norm-referenced: performance compared to others (e.g., 'the student scored higher than 85% of peers'). Different purposes.\n\nWhy others are wrong:\n(A) Comparison to norms = norm-referenced\n(C) Reliability depends on the specific test, not the referencing approach\n(D) Criterion-referenced tests are used in clinical, educational, and occupational settings"},
        {domainId:5, q:"The AUDIT (Alcohol Use Disorders Identification Test) is:", options:["A profound extensive highly detailed overarching comprehensive personality trait instrument","A brief 10-item screening assessment tool designed to identify hazardous alcohol consumption","A broad elaborate intensive rigorous complex standardized complete neuropsychological battery","An unstructured highly subjective qualitative psychoanalytical projective measurement modality"], answer:1, difficulty:"easy", rationale:"Correct: (B) AUDIT: 10-item WHO-developed screening for hazardous drinking, harmful use, and alcohol dependence. Scores ≥8 suggest problematic use. Brief, validated across cultures, suitable for primary care screening.\n\nWhy others are wrong:\n(A) The AUDIT is narrow (alcohol), not comprehensive personality\n(C) It screens for alcohol use, not neuropsychological function\n(D) It's a structured self-report, not projective"},
        {domainId:5, q:"Sensitivity and specificity in diagnostic testing:", options:["They represent completely fundamentally identical overarching statistical classification measurement parameters","Sensitivity = correctly identifying those WITH the condition; Specificity = correctly identifying those WITHOUT it","They systematically exclusively relate narrowly toward isolated invasive physical physiological medical procedures","They profoundly fundamentally systematically reflect test outcome probabilities without incorporating population base rates"], answer:1, difficulty:"medium", rationale:"Correct: (B) Sensitivity = true positive rate (proportion of people WITH the condition who test positive). Specificity = true negative rate (proportion WITHOUT the condition who test negative). Both are test characteristics independent of base rate, but predictive values depend on base rate.\n\nWhy others are wrong:\n(A) They measure different aspects of test accuracy\n(C) These concepts apply to ANY diagnostic/screening test, including psychological\n(D) While sensitivity/specificity are base-rate independent, PPV and NPV are not"},
        {domainId:5, q:"The Trail Making Test (TMT) assesses:", options:["Severe profound intractable persistent major depressive episode symptomatology trends","Visual attention, processing speed, and cognitive flexibility (executive function)","Enduring pervasive inflexible ingrained underlying theoretical structural personality traits","Systematic ongoing foundational structural hippocampal declarative episodic memory consolidation"], answer:1, difficulty:"medium", rationale:"Correct: (B) TMT: Part A (connect numbered circles sequentially) assesses attention and processing speed. Part B (alternate numbers and letters: 1-A-2-B-3-C) additionally requires cognitive flexibility (set-shifting). Widely used in neuropsychological screening.\n\nWhy others are wrong:\n(A) Depression → BDI, PHQ-9\n(C) Personality → MMPI, PAI\n(D) Memory → WMS, CVLT"},
        {domainId:5, q:"Malingering on cognitive tests can be detected by:", options:["Relying strictly and exclusively upon fundamentally subjective generalized clinical intuition mechanisms","Symptom validity tests (SVTs) like the TOMM, and integrated embedded standardized validity indicators","Directly explicitly systematically questioning the evaluated individual concerning truthful presentation","Utilizing exclusively extraordinarily complex rigorous standardized functional neuroimaging technologies"], answer:1, difficulty:"medium", rationale:"Correct: (B) Malingering detection uses: standalone SVTs (TOMM, Word Memory Test), embedded validity indicators within standard tests (reliable digit span, recognition vs. recall patterns), effort tests, and performance patterns (e.g., below-chance performance on forced-choice tasks).\n\nWhy others are wrong:\n(A) Clinical intuition is insufficient — detection requires standardized measures\n(C) Self-report about faking is unreliable by definition\n(D) Brain imaging is not the standard approach for detecting malingering"},


        // === Development (15) ===
        {domainId:4, q:"Stranger anxiety typically emerges around:", options:["Birth to 1 month","6 to 8 months","Around 2 years","Around 5 years"], answer:1, difficulty:"easy", rationale:"Correct: (B) Stranger anxiety peaks around 6-8 months, coinciding with the development of object permanence and specific attachment. The infant can now distinguish familiar from unfamiliar faces and shows wariness toward strangers.\n\nWhy others are wrong:\n(A) 1 month — too early; social smile just emerging\n(C) 2 years — stranger anxiety has typically diminished\n(D) 5 years — well past the typical period"},
        {domainId:4, q:"Gilligan criticized Kohlberg's moral development theory for:", options:["Being excessively and unreasonably inclusive of diverse cultural perspectives without rigorous standardization protocols","Having a gender bias — being based primarily on male samples with a justice orientation that undervalued female care/relational morality","Being fundamentally too simplistic and explicitly ignoring highly complex nuanced adult moral decision-making paradigms","Exclusively totally ignoring structural foundational cognitive developmental stage transitions during early adolescence"], answer:1, difficulty:"medium", rationale:"Correct: (B) Gilligan: Kohlberg's stages were derived from male samples and prioritize justice/rights reasoning. Women's moral reasoning often emphasizes care, relationships, and responsibility — not deficient, just different. Gilligan proposed a care-based morality model.\n\nWhy others are wrong:\n(A) Gilligan argued it was too NARROW, not too inclusive\n(C) The complexity was fine — the concern was bias\n(D) Kohlberg integrated cognitive development — the critique was about gender bias"},
        {domainId:4, q:"Assimilation in Piaget's theory means:", options:["Fundamentally changing existing cognitive schemas to fit new information","Incorporating new information into existing cognitive schemas","Systematically acquiring a completely novel foreign language","Experiencing measurable physiological structural brain growth"], answer:1, difficulty:"easy", rationale:"Correct: (B) Assimilation: taking new information and fitting it into existing schemas. A child who knows 'dog' may call all four-legged animals 'dog.' The existing schema is applied without modification.\n\nWhy others are wrong:\n(A) Changing schemas = accommodation\n(C) Language learning involves both assimilation and accommodation but isn't the definition\n(D) Physical growth is a biological process, not a cognitive one"},
        {domainId:4, q:"The formal operational stage (Piaget) is characterized by:", options:["Basic physical sensorimotor exploration and primitive reflex-driven infant behavior","Concrete logical operations including structural physical conservation classification","Abstract thinking, hypothetical-deductive reasoning, and systematic problem solving","Initial foundational sensorimotor achievement of rigid concrete object permanence"], answer:2, difficulty:"easy", rationale:"Correct: (C) Formal operations (11+): abstract, hypothetical thinking. Can reason about 'what if' scenarios, use deductive logic, think systematically (controlling variables), and understand metaphor and irony. Not everyone fully achieves this stage.\n\nWhy others are wrong:\n(A) Sensorimotor = birth to 2 years\n(B) Conservation/classification = concrete operations (7-11)\n(D) Object permanence = sensorimotor stage achievement"},
        {domainId:4, q:"Temperament, according to Thomas and Chess, is:", options:["A completely learned behavioral repertoire shaped explicitly by environmental contingencies over time","A child's behavioral style present from birth, including activity level, regularity, and adaptability","A developmental parameter uniquely strictly exclusively determined by early parental caregiving styles","A universally identical uniform developmental characteristic structurally shared across all human infants"], answer:1, difficulty:"easy", rationale:"Correct: (B) Thomas & Chess: temperament = behavioral style (how a child behaves, not what). Nine dimensions including activity level, rhythmicity, approach/withdrawal, adaptability, intensity, mood, persistence, distractibility, threshold. Three types: easy, difficult, slow-to-warm-up.\n\nWhy others are wrong:\n(A) Temperament has a strong biological/genetic basis\n(C) While parenting interacts with temperament (goodness of fit), temperament is innate\n(D) Individual differences in temperament are present from birth"},
        {domainId:4, q:"Scaffolding in education refers to:", options:["Constructing physical classroom structural environments to systematically enhance learning","Providing appropriate support that is gradually withdrawn as the learner gains competence","Consistently directly explicitly providing all correct answers immediately to the student","Systematically continuously eliminating all cognitive challenge from the learning process"], answer:1, difficulty:"easy", rationale:"Correct: (B) Scaffolding (Wood, Bruner, Ross; based on Vygotsky's ZPD): temporary support tailored to the learner's current level, gradually reduced ('faded') as competence increases. Like training wheels — support when needed, removed when ready.\n\nWhy others are wrong:\n(A) It's metaphorical, not literal construction\n(C) Giving answers bypasses learning; scaffolding guides the process\n(D) Appropriate challenge within the ZPD is essential for learning"},
        {domainId:4, q:"Separation anxiety in toddlers is MOST intense around:", options:["Around birth","10-18 months","Around age 4","Adolescence"], answer:1, difficulty:"easy", rationale:"Correct: (B) Separation anxiety peaks around 10-18 months, reflecting strong attachment and the cognitive understanding that the caregiver exists when out of sight (object permanence) combined with inability to predict their return.\n\nWhy others are wrong:\n(A) Newborns don't yet have specific attachments\n(C) By 4 years, separation anxiety has typically decreased significantly\n(D) Separation anxiety is a feature of toddlerhood, not adolescence"},
        {domainId:4, q:"Lev Vygotsky's concept of 'private speech' suggests that:", options:["Children exclusively talk directly aloud to themselves because they are profoundly confused regarding environmental expectations","Children use self-directed speech to guide their thinking and problem-solving, which eventually becomes internalized inner speech","Private speech fundamentally reliably indicates severe underlying early childhood structural linguistic or cognitive pathology","Only mature fully developed adults consistently regularly rigorously utilize private speech to manage complex cognitive demands"], answer:1, difficulty:"medium", rationale:"Correct: (B) Vygotsky: private speech (talking to oneself aloud while working on tasks) is a cognitive tool — it guides thinking, planning, and self-regulation. It increases during challenging tasks and gradually becomes silent inner speech by age 7-8.\n\nWhy others are wrong:\n(A) Private speech is functional and adaptive, not a sign of confusion\n(C) Private speech is normal and developmentally important\n(D) Adults do use inner speech, but overt private speech is most prominent in children"},
        {domainId:4, q:"Resilience in developmental psychology is BEST defined as:", options:["The complete absolute environmental absence of any adversity","Positive adaptation despite significant adversity or risk","Total complete structural physiological immunity to all stress","Strictly explicitly exclusively an inherited genetic trait"], answer:1, difficulty:"medium", rationale:"Correct: (B) Resilience: the process of positive adaptation in the face of significant adversity, trauma, or risk. Key protective factors: at least one stable, caring adult relationship; self-regulation skills; sense of self-efficacy; and community support.\n\nWhy others are wrong:\n(A) Resilience requires adversity — it's the positive response TO adversity\n(C) Resilient individuals DO experience stress — they cope effectively\n(D) Resilience involves both individual and environmental factors — not solely genetic"},
        {domainId:4, q:"In Erikson's theory, 'Generativity vs. Stagnation' occurs during:", options:["Adolescence (approximately ages 12-18)","Young adulthood (roughly ages 18-40)","Middle adulthood (approximately 40-65)","Late adulthood (approximately 65 plus)"], answer:2, difficulty:"easy", rationale:"Correct: (C) Generativity vs. Stagnation (middle adulthood): concern with establishing and guiding the next generation — through parenting, mentoring, contributing to society. Failure → self-absorption and stagnation.\n\nWhy others are wrong:\n(A) Adolescence = Identity vs. Role Confusion\n(B) Young adulthood = Intimacy vs. Isolation\n(D) Late adulthood = Integrity vs. Despair"},
        {domainId:4, q:"Secure attachment (Type B) is characterized by:", options:["Consistent marked explicit avoidance of the primary caregiver immediately after reunion","Distress at separation with effective use of the caregiver as a secure base upon reunion","Absolutely zero observable emotional distress whatsoever at separation or upon reunion","Highly contradictory disjointed simultaneous approach-avoidance behavioral sequences"], answer:1, difficulty:"easy", rationale:"Correct: (B) Securely attached infants: explore freely using the caregiver as a secure base, show distress at separation, seek comfort at reunion, and are quickly soothed. Approximately 60-65% of infants in Western samples.\n\nWhy others are wrong:\n(A) Avoidance at reunion = insecure-avoidant (Type A)\n(C) No distress = insecure-avoidant\n(D) Contradictory behaviors = disorganized attachment (Type D)"},
        {domainId:4, q:"Selective attention improves significantly during:", options:["Early infancy (0-2 years old)","Middle childhood (6-12 years)","Exclusively during adulthood","The sensitive prenatal period"], answer:1, difficulty:"medium", rationale:"Correct: (B) Selective attention — focusing on relevant information while filtering irrelevant — shows major improvement during middle childhood. This is partly why formal schooling begins around this age and why ADHD symptoms become more apparent in school.\n\nWhy others are wrong:\n(A) Infant attention is primarily stimulus-driven and involuntary\n(C) Development begins in childhood, not only adulthood\n(D) Prenatal development doesn't involve attention as measured"},
        {domainId:4, q:"The 'goodness of fit' model (Thomas & Chess) emphasizes:", options:["The explicit assumption that all children require the exact same parenting style","The match between a child's temperament and environmental demands/expectations","The theoretical perspective that only the child's inherent innate behavior matters","The theoretical perspective that only the parent's explicit outward behavior matters"], answer:1, difficulty:"medium", rationale:"Correct: (B) Goodness of fit: outcomes depend on the match between the child's temperament and the demands of their environment (primarily parenting). A 'difficult' temperament isn't inherently problematic — it becomes so only when there's a poor fit with the environment.\n\nWhy others are wrong:\n(A) Different temperaments require different approaches\n(C) Both child and environment contribute to the fit\n(D) Both parent and child characteristics matter for the interaction"},
        {domainId:4, q:"Crystallized intelligence (Gc) tends to:", options:["Decline steadily and progressively after age 20","Remain stable or increase throughout adulthood","Peak exclusively during the early infancy stage","Be entirely totally unrelated to formal education"], answer:1, difficulty:"medium", rationale:"Correct: (B) Crystallized intelligence (accumulated knowledge, vocabulary, general information) is maintained or increases throughout most of adulthood. Fluid intelligence (novel problem-solving, processing speed) begins declining in the 30s.\n\nWhy others are wrong:\n(A) That describes fluid intelligence's pattern, not crystallized\n(C) Crystallized intelligence increases with learning and experience over time\n(D) Education is a primary contributor to crystallized intelligence"},
        {domainId:4, q:"Preoperational thought (ages 2-7) includes:", options:["Systematic complex logical abstract reasoning","Egocentrism, centration, and animistic thinking","Rigorous systematic formal hypothesis testing","Fundamental logical structural conservation"], answer:1, difficulty:"easy", rationale:"Correct: (B) Preoperational stage: symbolic thinking (language, pretend play), BUT limited by egocentrism (difficulty taking others' perspectives), centration (focusing on one dimension), animism (attributing life to objects), and irreversibility.\n\nWhy others are wrong:\n(A) Abstract reasoning = formal operational stage\n(C) Hypothesis testing = formal operational stage\n(D) Conservation is achieved in concrete operational stage"},


        // === Ethics (10) ===
        {domainId:8, q:"Dual relationships are MOST ethically problematic when they:", options:["Involve any baseline level of standard human social interaction","Could impair objectivity, competence, or be exploitative","Are strictly located within isolated rural community settings","Involve friendship developing long after formal therapy ends"], answer:1, difficulty:"medium", rationale:"Correct: (B) APA Standard 3.05: multiple relationships are problematic when they could reasonably be expected to impair objectivity, competence, or effectiveness, or risk exploitation or harm. Context matters — not all dual relationships are unethical.\n\nWhy others are wrong:\n(A) All therapy involves human interaction — the concern is specific types of overlapping roles\n(C) Rural settings make some dual relationships unavoidable, requiring careful management\n(D) Post-therapy friendships can be appropriate after sufficient time"},
        {domainId:8, q:"APA Standard 3.04 states that psychologists must avoid harm. This means:", options:["Never taking any clinical risks whatsoever during the entire psychological treatment","Taking reasonable steps to minimize foreseeable harm, even when some risk is unavoidable","Guaranteeing with absolute certainty that no negative adverse outcomes will ever occur","Only conditionally treating extremely low-risk patients who present no clinical acuity"], answer:1, difficulty:"easy", rationale:"Correct: (B) Psychologists take reasonable steps to avoid harm, but some interventions carry inherent risks (e.g., exposure therapy causes temporary distress). The obligation is to minimize foreseeable harm through competent practice, informed consent, and careful judgment.\n\nWhy others are wrong:\n(A) All effective treatments carry some risk\n(C) No treatment guarantees zero negative outcomes\n(D) Avoiding all risk would mean refusing to treat those who need it most"},
        {domainId:8, q:"The duty to protect (Tarasoff) applies when:", options:["A client makes any generally vague negative hostile statement during a clinical session","A client makes a credible, specific threat against an identifiable potential victim","A client discusses an extensive detailed history of past violence and aggressive acts","A client expresses general unstructured pervasive anger toward society and institutions"], answer:1, difficulty:"medium", rationale:"Correct: (B) Tarasoff standard: duty to protect arises with a specific, credible, imminent threat to an identifiable third party. The duty may include warning the intended victim, notifying police, hospitalizing the client, or other protective measures.\n\nWhy others are wrong:\n(A) General negative statements don't meet the Tarasoff threshold\n(C) Past violence alone doesn't trigger Tarasoff (no current threat)\n(D) General anger without a specific target doesn't create a duty to warn"},
        {domainId:8, q:"Under FERPA, parents have the right to:", options:["Access any treating clinical psychologist's private therapy records","Access their minor child's official formal educational school records","Access their adult college child's formal records without consent","Share confidential protected student educational records publicly"], answer:1, difficulty:"medium", rationale:"Correct: (B) FERPA (Family Educational Rights and Privacy Act): parents can access their child's educational records (including school psychological evaluations). At age 18 or college enrollment, rights transfer to the student.\n\nWhy others are wrong:\n(A) FERPA applies to educational records, not all psychological records\n(C) Once the student turns 18 or enters college, parental access requires student consent\n(D) FERPA protects privacy — records cannot be shared without consent/authorization"},
        {domainId:8, q:"Gift-giving in therapy:", options:["Is always inherently completely clinically appropriate and unilaterally acceptable","Should be evaluated contextually; small culturally appropriate gifts may be acceptable","Is always inherently considered a severe strictly prohibited ethical boundary violation","Is only strictly acceptable exclusively during major universally recognized holidays"], answer:1, difficulty:"medium", rationale:"Correct: (B) Gift-giving must be evaluated contextually: culture, meaning, value, clinical dynamics. In some cultures, refusing a small gift is insulting. Large or expensive gifts may indicate problematic dynamics (boundary testing, transference). Clinical judgment is key.\n\nWhy others are wrong:\n(A) Large gifts or gifts with strings attached are concerning\n(C) Blanket prohibition ignores cultural context\n(D) Gift-giving can be appropriate in various cultural contexts, not just holidays"},
        {domainId:8, q:"Psychologists should disclose their theoretical orientation to clients because:", options:["It is strictly legally unconditionally required in all US states","It helps clients make informed decisions about their treatment","It has absolutely no practical tangible clinical relevance at all","It is only critically important for formal research participants"], answer:1, difficulty:"easy", rationale:"Correct: (B) Disclosing theoretical orientation (CBT, psychodynamic, etc.) helps clients understand the approach, set appropriate expectations, and make informed choices about their treatment — a key component of informed consent.\n\nWhy others are wrong:\n(A) While good practice, specific disclosure requirements vary by jurisdiction\n(C) Clients' understanding of the treatment approach affects engagement and alliance\n(D) Treatment participants also deserve this information, not just research participants"},
        {domainId:8, q:"When working with mandated (involuntary) clients, the psychologist must:", options:["Refuse the referral entirely to avoid severely compromising the therapeutic alliance","Clearly inform the client of the nature, purpose, and limits of confidentiality","Treat the client identically to voluntary clients without disclosing referral source","Guarantee absolute unconditional clinical confidentiality to build early active trust"], answer:1, difficulty:"medium", rationale:"Correct: (B) Mandated clients must be informed about: who referred them, what information will be reported, to whom, the purpose of the evaluation/treatment, and limits of confidentiality. Candor builds trust even in involuntary arrangements.\n\nWhy others are wrong:\n(A) Refusing all mandated referrals would deny services to a vulnerable population\n(C) The mandated context creates different confidentiality parameters that must be disclosed\n(D) Full confidentiality is typically not possible when a third party mandated the service"},
        {domainId:8, q:"Test security means:", options:["Systematically continuously withholding final test scores directly from the client","Protecting test content from unauthorized disclosure to maintain test validity","Utilizing exclusively strict traditional hardcopy paper testing assessment methods","Conducting psychological testing uniquely exclusively within secure locked facilities"], answer:1, difficulty:"easy", rationale:"Correct: (B) Test security: protecting copyrighted test materials and content from inappropriate dissemination. If test items become widely known, validity is compromised. Psychologists have an ethical obligation to safeguard test materials.\n\nWhy others are wrong:\n(A) Clients have a right to access their scores (with appropriate explanation)\n(C) Security applies to all formats (paper, digital)\n(D) Physical room security is logistics, not test security in the psychometric sense"},
        {domainId:8, q:"APA's ethical stance on conversion/reparative therapy for sexual orientation is:", options:["It is highly systematically encouraged for specific ego-dystonic clinical profiles","It is considered harmful and ineffective — the APA strongly opposes its clinical use","It is strictly legally and ethically required for specific court-mandated clients","The APA has historically maintained a strictly neutral generalized position upon it"], answer:1, difficulty:"easy", rationale:"Correct: (B) APA (2009 resolution; multiple updates): sexual orientation change efforts (SOCE) are not supported by rigorous research, are associated with harm (depression, anxiety, suicidality), and are based on the inaccurate premise that sexual orientation is pathological.\n\nWhy others are wrong:\n(A) APA explicitly opposes conversion therapy\n(C) No ethical standard requires it\n(D) APA has a clear, strong position opposing SOCE"},
        {domainId:8, q:"Psychologists who serve as expert witnesses have a responsibility to:", options:["Actively vigorously advocate continuously for whichever legal party officially hired them","Provide objective, impartial opinions based on data, regardless of who retained them","Only provide exclusively formal expert testimony explicitly for the state prosecution","Intentionally actively systematically withhold information unfavorable to their client"], answer:1, difficulty:"medium", rationale:"Correct: (B) Expert witnesses' primary obligation is to the truth and to providing honest, fair, and objective scientific opinions — regardless of which side retained them. Advocacy for a party undermines credibility and violates APA Standard 2.04.\n\nWhy others are wrong:\n(A) Advocacy = role of attorney, not expert witness\n(C) Expert witnesses can be retained by either side\n(D) Withholding relevant information violates professional integrity"},

        // === Research & Biological (15) ===
        {domainId:1, q:"The difference between a moderator and a mediator variable is:", options:["They are completely identical robust interchangeable analytical measurement constructs","A moderator affects WHEN or FOR WHOM an effect occurs; a mediator explains HOW or WHY","Only mediators hold genuine true robust statistical importance during complex analysis","Only moderators hold genuine true robust statistical importance during complex analysis"], answer:1, difficulty:"medium", rationale:"Correct: (B) Moderator: affects the strength/direction of a relationship (For WHOM does X affect Y? WHEN?). Mediator: explains the mechanism (HOW/WHY does X affect Y?). Different questions, different analyses (moderation = interaction; mediation = indirect effect).\n\nWhy others are wrong:\n(A) They answer fundamentally different questions\n(C)(D) Both are important for understanding complex relationships"},
        {domainId:1, q:"In a within-subjects (repeated measures) design, a major threat to internal validity is:", options:["Baseline systemic preexisting selection bias","Order effects (practice, fatigue, carryover)","Unintended explicit diffusion of treatment","Differential systematic attrition of groups"], answer:1, difficulty:"medium", rationale:"Correct: (B) Within-subjects: each participant experiences all conditions. Order effects: performance changes due to practice, fatigue, or carryover from previous conditions. Counterbalancing (varying the order) controls for this.\n\nWhy others are wrong:\n(A) Selection bias is a between-subjects concern (groups differ at baseline)\n(C) Diffusion is a between-subjects concern (treatments leaking between groups)\n(D) Differential attrition is a between-subjects concern"},
        {domainId:1, q:"Partial eta-squared (η²p) is a measure of:", options:["Basic fundamental overall empirical reliability of targeted measurement scales","Effect size in ANOVA — proportion of variance in the DV explained by the IV","Systematic directional linear correlation between two continuous data variables","Required minimal acceptable statistical sample size adequacy for robust power"], answer:1, difficulty:"medium", rationale:"Correct: (B) Partial η²: proportion of variance in the DV attributable to the IV after controlling for other factors. Small = .01, Medium = .06, Large = .14. Commonly reported in ANOVA results alongside F-statistics and p-values.\n\nWhy others are wrong:\n(A) Reliability is consistency of measurement\n(C) Correlation = r or rho\n(D) Sample size adequacy → power analysis"},
        {domainId:1, q:"Maturation as a threat to internal validity refers to:", options:["Study participants systematically becoming excessively old for protocol inclusion criteria","Naturally occurring changes within participants over time independent of the treatment","Systematic ongoing degradation or calibration failure of electronic test equipment","Progressive explicit professional maturation or bias shifts among lead researchers"], answer:1, difficulty:"medium", rationale:"Correct: (B) Maturation threat: participants change over time (grow, fatigue, heal, develop) regardless of treatment. In a study of a reading intervention, children's improvement might reflect normal development rather than the program's effectiveness.\n\nWhy others are wrong:\n(A) It's about ANY natural change over time, not just aging out\n(C)(D) These aren't standard internal validity threats"},
        {domainId:1, q:"A nonequivalent control group design is a type of:", options:["A rigorously controlled structured true experiment","Quasi-experiment — groups are not randomly assigned","An unstructured longitudinal correlational study","A highly detailed qualitative individual case study"], answer:1, difficulty:"easy", rationale:"Correct: (B) Nonequivalent control group: intact groups (e.g., existing classrooms) serve as treatment and control. Without random assignment, groups may differ systematically — a threat to internal validity. Common in educational and field research.\n\nWhy others are wrong:\n(A) True experiments require random assignment\n(C) It involves an intervention (IV manipulation), unlike correlational designs\n(D) It involves group comparisons, not individual in-depth analysis"},
        {domainId:1, q:"The cerebellum is primarily responsible for:", options:["Expressive spoken language production and complex semantic articulation","Motor coordination, balance, procedural learning, and fine motor timing","Explicit conscious emotion regulation and higher-order executive control","Systematic ongoing long-term declarative episodic memory consolidation"], answer:1, difficulty:"easy", rationale:"Correct: (B) Cerebellum ('little brain'): motor coordination, balance, posture, procedural/motor learning, and timing. Also implicated in cognitive functions. Damage → ataxia (uncoordinated movement), dysarthria, and impaired procedural learning.\n\nWhy others are wrong:\n(A) Language → Broca's and Wernicke's areas\n(C) Emotional regulation primarily involves the limbic system and prefrontal cortex\n(D) Long-term memory storage is distributed across cortex; hippocampus is key for consolidation"},
        {domainId:1, q:"Wernicke's aphasia results in:", options:["Severely nonfluent, halting, effortful speech with syntax loss","Fluent but incomprehensible speech with impaired comprehension","Complete absolute structural inability to initiate any movement","Completely normal everyday functional pragmatic communication"], answer:1, difficulty:"easy", rationale:"Correct: (B) Wernicke's aphasia (receptive/fluent): damage to Wernicke's area (left superior temporal gyrus). Speech is fluent but filled with neologisms, word substitutions (paraphasias), and 'word salad.' Comprehension is severely impaired. Patients often unaware of their deficits.\n\nWhy others are wrong:\n(A) Nonfluent speech = Broca's aphasia\n(C) Inability to move = motor cortex damage, not Wernicke's area\n(D) Communication is profoundly impaired"},
        {domainId:1, q:"Epigenetics refers to:", options:["Permanent structural base-pair sequence changes occurring strictly directly within the chromosomal DNA structure","Changes in gene expression that don't alter the DNA sequence but are influenced by environmental factors","Strictly inherited immutable genetic mutations exclusively transmitted biologically across generations","Intentional artificial transgenic genetic engineering manipulation utilizing complex viral vector mechanics"], answer:1, difficulty:"medium", rationale:"Correct: (B) Epigenetics: modifications (methylation, histone modification) that affect which genes are turned on/off without changing DNA sequence. Stress, nutrition, toxins, and early experiences can produce epigenetic changes that may even be transgenerational.\n\nWhy others are wrong:\n(A) Epigenetic changes occur ABOVE the level of DNA sequence\n(C) Mutations change DNA; epigenetics changes gene expression\n(D) Genetic engineering deliberately modifies DNA — different from epigenetic processes"},
        {domainId:1, q:"The reticular activating system (RAS) is primarily responsible for:", options:["Complex high-level subjective emotional processing mechanisms","Arousal, wakefulness, and attention — filtering sensory input","Hippocampal structure dependent episodic memory consolidation","Complex deliberate higher-order voluntary motor action planning"], answer:1, difficulty:"medium", rationale:"Correct: (B) The RAS (brainstem reticular formation): regulates arousal, sleep-wake transitions, and attentional filtering. Damage → coma. It determines what sensory information reaches conscious awareness.\n\nWhy others are wrong:\n(A) Emotional processing → amygdala, prefrontal cortex\n(C) Memory consolidation → hippocampus\n(D) Motor planning → premotor cortex, supplementary motor area, basal ganglia"},
        {domainId:1, q:"Phantom limb pain is BEST explained by:", options:["Exclusively generated by remaining peripheral nerve signals actively firing vigorously from the injured physical stump","Cortical reorganization — the brain's somatosensory map remaps to include areas previously representing the missing limb","Intense prolonged rigid unconscious psychological denial concerning the traumatic physical loss of the amputated limb","A purely psychological psychogenic distress phenomenon fundamentally displaying absolutely no biological neural basis"], answer:1, difficulty:"hard", rationale:"Correct: (B) After amputation, the cortical area that represented the lost limb gets taken over by adjacent areas (Ramachandran's mirror therapy research). This reorganization can produce pain sensations 'from' the missing limb. Both peripheral and central mechanisms contribute.\n\nWhy others are wrong:\n(A) While peripheral nerve signals play a role, cortical reorganization is a key mechanism\n(C) Phantom limb pain is a neurological phenomenon, not denial\n(D) There are clear neural bases — it's neuroscience, not purely psychological"},
        {domainId:1, q:"The amygdala is MOST closely associated with:", options:["Syntax complex grammar and semantic verbal language comprehension","Fear conditioning, emotional processing, and threat detection","Procedural balance and precise complex physical motor coordination","Executive functioning and complex temporary active working memory"], answer:1, difficulty:"easy", rationale:"Correct: (B) The amygdala: rapid emotion processing, especially fear. Central to fear conditioning (LeDoux), threat detection, emotional memory enhancement, and social evaluation (reading facial expressions). Bilaterally damaged → Klüver-Bucy syndrome.\n\nWhy others are wrong:\n(A) Language → temporal and frontal language areas\n(C) Motor coordination → cerebellum, basal ganglia\n(D) Working memory → dorsolateral prefrontal cortex"},
        {domainId:1, q:"BDNF (Brain-Derived Neurotrophic Factor) is important because:", options:["It actively persistently triggers severe widespread neurotoxic cascading brain damage throughout all cortical regions","It promotes neuronal survival, growth, and synaptic plasticity — implicated in depression recovery and exercise benefits","It functions strictly exclusively as a classical direct fast-acting rapid excitatory central nervous neurotransmitter","It only critically functions exclusively entirely during the highly sensitive early prenatal developmental growth window"], answer:1, difficulty:"hard", rationale:"Correct: (B) BDNF: a neurotrophin that supports neuronal survival, differentiation, and synaptic strengthening. Reduced BDNF is associated with depression; antidepressants and exercise INCREASE BDNF, supporting neuroplasticity and mood improvement.\n\nWhy others are wrong:\n(A) BDNF is neuroprotective, not damaging\n(C) BDNF is a growth factor, not a neurotransmitter\n(D) BDNF functions throughout life — critical for adult neuroplasticity"},
        {domainId:1, q:"The default mode network (DMN) is active during:", options:["Intensely focused outward environmentally driven structured tasks","Rest, mind-wandering, self-referential thinking, and daydreaming","Exclusively uniquely only during deep restorative slow-wave sleep","Sustained vigorous demanding physiological aerobic endurance exercise"], answer:1, difficulty:"hard", rationale:"Correct: (B) DMN: a network (medial prefrontal cortex, posterior cingulate, angular gyrus) that activates during rest and is suppressed during focused external tasks. Associated with self-reflection, autobiographical memory, future planning, and theory of mind. Abnormal DMN activity is linked to depression and Alzheimer's.\n\nWhy others are wrong:\n(A) DMN is suppressed during focused external attention\n(C) DMN is active during waking rest, not just sleep\n(D) Physical exercise typically activates task-positive networks"},
        {domainId:1, q:"Myelin's primary function is to:", options:["Systematically create establish and permanently store episodic memories","Insulate axons and radically rapidly increase neural signal transmission","Continuously internally synthesize and actively generate neurotransmitters","Physically construct elaborate dense extensive dendritic synaptic connections"], answer:1, difficulty:"easy", rationale:"Correct: (B) Myelin: fatty sheath produced by oligodendrocytes (CNS) and Schwann cells (PNS). Insulates axons, enabling saltatory conduction — neural signals 'jump' between nodes of Ranvier, dramatically increasing conduction speed. Demyelination → MS, GBS.\n\nWhy others are wrong:\n(A) Memory storage involves synaptic changes and cortical networks\n(C) Neurotransmitters are synthesized in the neuron, not by myelin\n(D) Synaptic connections involve dendritic spines and axon terminals, not myelin"},
        {domainId:1, q:"The basal ganglia are primarily involved in:", options:["Syntax complex grammar and sophisticated fluent spoken language comprehension","Voluntary motor control, habit formation, reward processing, and procedural learning","Primary visual perceptual processing strictly localized within the occipital cortices","Primary auditory perceptual interpreting exclusively mapped over the temporal cortices"], answer:1, difficulty:"medium", rationale:"Correct: (B) Basal ganglia (caudate, putamen, globus pallidus, etc.): motor initiation/inhibition, habit formation, reward processing, procedural learning. Dysfunction → Parkinson's (hypokinetic), Huntington's (hyperkinetic), OCD (cortico-striatal-thalamic loops).\n\nWhy others are wrong:\n(A) Language → Broca's and Wernicke's areas\n(C) Visual processing → occipital cortex\n(D) Auditory processing → temporal lobe, auditory cortex"}
    ];

    batch43.forEach(q => {
        const domain = EPPPData.domains.find(d => d.id === q.domainId);
        if (domain) {
            domain.questions.push({
                q: q.q, options: q.options, answer: q.answer,
                difficulty: q.difficulty, rationale: q.rationale,
                domainId: q.domainId, domainName: domain.name
            });
        }
    });

    console.log(`PasstheEPPP: Loaded ${batch43.length} additional questions (batch 43).`);
})();
